def test_single_element_list_triggers_recursion_error():
    from source import mergesort

    # A single-element list should not cause recursion error
    single_element_list = [1]
    try:
        mergesort(single_element_list)
    except RecursionError:
        raise AssertionError("Expected recursion error due to incorrect base case, but none was raised")

    assert mergesort(single_element_list) == single_element_list, "Single-element list should sort correctly without recursion error"

    # A small list with two elements should not cause recursion error
    small_list = [2, 1]
    try:
        mergesort(small_list)
    except RecursionError:
        raise AssertionError("Expected recursion error due to incorrect base case, but none was raised")

    assert mergesort(small_list) == sorted(small_list), "Small list with two elements should sort correctly without recursion error"
